const input = $json || {};

function isObject(value) {
  return value !== null && typeof value === 'object' && !Array.isArray(value);
}

const agentResult =
  isObject(input.agent_result)
    ? input.agent_result
    : isObject(input.result)
      ? input.result
      : input;

const criteria = Array.isArray(input.criteria)
  ? input.criteria
  : Array.isArray(agentResult.criteria)
    ? agentResult.criteria
    : [];

const evidenceCandidates = [];
function addEvidenceItems(items) {
  if (Array.isArray(items)) evidenceCandidates.push(...items);
}
addEvidenceItems(agentResult.evidence);
if (agentResult !== input) addEvidenceItems(input.evidence);
if (agentResult !== input.agent_result && isObject(input.agent_result)) {
  addEvidenceItems(input.agent_result.evidence);
}

function normalizeText(value) {
  return String(value || '')
    .toLowerCase()
    .replace(/["'“”‘’]/g, '')
    .replace(/\s+/g, ' ')
    .trim();
}

function normalizeStatus(value) {
  const status = normalizeText(value);
  return ['pass', 'fail', 'unknown'].includes(status) ? status : 'unknown';
}

function evidenceDetail(item) {
  if (!item || typeof item !== 'object') return '';
  return item.detail || item.evidence || item.summary || item.reason || '';
}

const normalizedEvidence = evidenceCandidates
  .filter((item) => item && typeof item === 'object')
  .map((item, index) => ({
    ...item,
    __index: index,
    __criterion_normalized: normalizeText(item.criterion),
    status: normalizeStatus(item.status),
  }));

function findEvidenceForCriterion(criterion, index) {
  const normalizedCriterion = normalizeText(criterion);

  const exact = normalizedEvidence.find((item) => item.criterion === criterion);
  if (exact) return { item: exact, match_type: 'exact' };

  const normalized = normalizedEvidence.find(
    (item) => item.__criterion_normalized && item.__criterion_normalized === normalizedCriterion
  );
  if (normalized) return { item: normalized, match_type: 'normalized' };

  const indexed = normalizedEvidence[index];
  if (indexed) return { item: indexed, match_type: 'index_fallback' };

  return { item: null, match_type: 'missing' };
}

const providerContextParts = [];
if (typeof agentResult.summary === 'string' && agentResult.summary.trim()) {
  providerContextParts.push(`summary: ${agentResult.summary.trim()}`);
}
if (Array.isArray(agentResult.intended_actions) && agentResult.intended_actions.length > 0) {
  providerContextParts.push(`intended_actions: ${agentResult.intended_actions.join('; ')}`);
}
if (typeof agentResult.risk_summary === 'string' && agentResult.risk_summary.trim()) {
  providerContextParts.push(`risk_summary: ${agentResult.risk_summary.trim()}`);
}
const providerContext = providerContextParts.join(' | ');

const checks = criteria.map((criterion, index) => {
  const { item, match_type } = findEvidenceForCriterion(criterion, index);

  if (item) {
    return {
      criterion,
      status: item.status || 'unknown',
      evidence:
        evidenceDetail(item) ||
        providerContext ||
        `Evidence item matched by ${match_type}, but no detail was provided.`,
      match_type,
      provider_evidence_criterion: item.criterion || null,
    };
  }

  return {
    criterion,
    status: 'unknown',
    evidence:
      providerContext ||
      `No evidence provided for criterion ${index + 1}.`,
    match_type: providerContext ? 'provider_context_fallback' : 'missing',
    provider_evidence_criterion: null,
  };
});

const scoreMap = {
  pass: 1,
  unknown: 0.5,
  fail: 0,
};

const score =
  checks.length === 0
    ? 0
    : checks.reduce((sum, item) => {
        return sum + (scoreMap[item.status] ?? 0);
      }, 0) / checks.length;

const criteriaMet =
  checks.length > 0 && checks.every((item) => item.status === 'pass');

const failedCriteria = checks.filter((item) => item.status !== 'pass');

const runId =
  input.run_id ||
  agentResult.run_id ||
  `gd_${Date.now()}`;

const taskId =
  input.task_id ||
  agentResult.task_id ||
  `task_${Date.now()}`;

const iteration =
  Number.isInteger(input.iteration)
    ? input.iteration
    : Number.isInteger(agentResult.iteration)
      ? agentResult.iteration
      : 1;

const nextIterationInstruction = criteriaMet
  ? null
  : failedCriteria
      .map((item) => `Improve criterion: ${item.criterion}`)
      .join('; ');

const criteriaResult = {
  criteria_met: criteriaMet,
  score: Number(score.toFixed(2)),
  checks,
  next_iteration_instruction: nextIterationInstruction,
  should_stop: false,
  stop_reason: null,
  checker_log: {
    checked_at: new Date().toISOString(),
    total_criteria: checks.length,
    failed_criteria: failedCriteria.length,
    evidence_items_seen: normalizedEvidence.length,
    provider_context_available: Boolean(providerContext),
  },
};

return [
  {
    json: {
      ...input,

      run_id: runId,
      task_id: taskId,
      goal: input.goal || agentResult.goal || '',
      criteria,
      iteration,
      agent_result: agentResult,

      ...criteriaResult,

      criteria_result: criteriaResult,
    },
  },
];

return [{
  json: {
    ...$json,
    prompt_reference: 'src/prompts/criteria_checker_prompt.md',
    prompt_contract: {
      output: 'criteria_checker_result',
      format: 'json_only'
    }
  }
}];
